// Detect if running as Android APK
const isAndroid = typeof window.Capacitor !== "undefined";
const isAndroidNative = isAndroid && window.Capacitor?.getPlatform?.() === "android";

// ── PERSISTENT STORAGE ───────────────────────────────────────────────────────
const STORAGE_KEY = "vaibhav_app_data";

async function nativeGet(key) {
  try {
    if(isAndroidNative && window.Capacitor?.Plugins?.PersistentStorage){
      const r = await window.Capacitor.Plugins.PersistentStorage.get({key});
      if(r && r.value) return JSON.parse(r.value);
    }
  } catch(e) {}
  try {
    const raw = localStorage.getItem(key);
    if(raw) return JSON.parse(raw);
  } catch(e) {}
  return null;
}

async function nativeSet(key, value) {
  const str = JSON.stringify(value);
  try { localStorage.setItem(key, str); } catch(e) {}
  try {
    if(isAndroidNative && window.Capacitor?.Plugins?.PersistentStorage){
      await window.Capacitor.Plugins.PersistentStorage.set({key, value: str});
    }
  } catch(e) {}
}

async function nativeRemove(key) {
  try { localStorage.removeItem(key); } catch(e) {}
  try {
    if(isAndroidNative && window.Capacitor?.Plugins?.PersistentStorage){
      await window.Capacitor.Plugins.PersistentStorage.remove({key});
    }
  } catch(e) {}
}

function loadUserProfile() {
  try {
    const raw = localStorage.getItem("vaibhav_profile");
    if(raw) return JSON.parse(raw);
  } catch(e) {}
  return null;
}

function saveUserProfile(profile) {
  try { localStorage.setItem("vaibhav_profile", JSON.stringify(profile)); } catch(e) {}
  nativeSet("vaibhav_profile", profile);
}

