function daysUntil(d){if(!d)return null;return Math.ceil((new Date(d)-new Date().setHours(0,0,0,0))/86400000);}
function getInitials(n){if(!n)return"?";return n.split(" ").map(w=>w[0]).join("").toUpperCase().slice(0,2);}
function todayStr(){return new Date().toLocaleDateString("en-IN",{weekday:"long",day:"numeric",month:"long",year:"numeric"});}
function formatDate(d){if(!d)return"Not set";return new Date(d).toLocaleDateString("en-IN",{day:"numeric",month:"long",year:"numeric"});}

